// Parse Lightspeed jobs from HTML
const items = $input.all();
const html = String(items[0]?.json?.data || items[0]?.json || '');
const results = [];
const seen = new Set();

// CX-relevant keywords
const cxKeywords = ['customer', 'support', 'success', 'experience', 'cx', 'service', 'solutions', 'implementation', 'onboarding', 'account manager', 'technical account', 'client'];

// Split by job card boundaries - look for job listing items
const cards = html.split(/class="[^"]*job-boards-job[^"]*"/);

for (const card of cards) {
  // Extract job title
  const titleMatch = card.match(/class="[^"]*job-boards-job-title[^"]*"[^>]*>([^<]+)</);
  if (!titleMatch) continue;
  const title = titleMatch[1].trim();

  // Filter for CX-relevant roles
  const titleLower = title.toLowerCase();
  const isCxRelevant = cxKeywords.some(kw => titleLower.includes(kw));
  if (!isCxRelevant) continue;

  // Extract company name
  const companyMatch = card.match(/class="[^"]*job-boards-job-company[^"]*"[^>]*>([^<]+)</);
  const company = companyMatch ? companyMatch[1].trim() : '';

  // Extract job URL
  const urlMatch = card.match(/href="([^"]*lever\.co[^"]*|[^"]*greenhouse\.io[^"]*|[^"]*ashbyhq\.com[^"]*|[^"]*jobs\.lsvp\.com\/jobs\/[^"]+\/[^"]+)"/i);
  const jobUrl = urlMatch ? urlMatch[1] : '';

  // Extract location
  const locationMatch = card.match(/class="[^"]*job-boards-job-location[^"]*"[^>]*>([^<]+)</);
  const location = locationMatch ? locationMatch[1].trim() : 'Remote';

  // Dedup by company+title
  const key = (company + ':' + title).toLowerCase().replace(/[^a-z0-9]/g, '');
  if (seen.has(key)) continue;
  seen.add(key);

  results.push({
    json: {
      'Job Title': title,
      'Job URL': jobUrl,
      'Company': company,
      'Location': location,
      'Source': 'Lightspeed',
      'Source Detail': 'lightspeed-jobs-board'
    }
  });
}

if (results.length === 0) {
  const hasJobItems = html.includes('job-boards-job');
  return [{ json: { _empty: true, _message: 'No CX jobs found', htmlLength: html.length, hasJobItems: hasJobItems } }];
}

return results;
